import java.io.FileWriter;
import java.io.IOException;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitize and encode user input to prevent XSS
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String sanitizedInput = codec.encodeForHTML(userInput);

        // Properly handling user input by encoding it before outputting it to the webpage
        FileWriter writer = new FileWriter("output.html");
        writer.write("<html>");
        writer.write("<body>");
        writer.write("<h1>Welcome " + sanitizedInput + "</h1>");
        writer.write("</body>");
        writer.write("</html>");

        writer.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
